import { useMemo, useState } from 'react';
import { BracketsPlus } from '@untitledui/icons';
import { MenuTrigger as AriaMenuTrigger } from 'react-aria-components';
import { Button } from '@/components/atoms/Button';
import { InputSearchField } from '@/components/atoms/Input';
import {
  MenuList,
  MenuPopover,
  MenuItem as MenuItemPrimitive,
} from '@/components/molecules/Menu/MenuPrimitives';
import { cx } from '@/utils/cx';
import { WithDataId } from '@/types/withDataId';
import { formatTemplate } from './_utils';

interface TemplaterMenuProps extends WithDataId {
  templateItems: string[];
  onSelect: (item: string) => void;
  className?: string;
  isFormatTemplateItems?: boolean;
  isDisabled?: boolean;
}

export function TemplaterMenu({
  templateItems,
  onSelect,
  isFormatTemplateItems = true,
  className = '',
  'data-id': dataId,
  isDisabled,
}: TemplaterMenuProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredItems = useMemo(() => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) return templateItems;
    return templateItems.filter((item) => item.toLowerCase().includes(query));
  }, [templateItems, searchTerm]);

  const handleOpenChange = (open: boolean) => {
    setIsOpen(open);
    if (!open) setSearchTerm('');
  };

  return (
    <AriaMenuTrigger
      isOpen={isOpen}
      onOpenChange={handleOpenChange}
    >
      <Button
        color="tertiary"
        className={cx('outline-hidden size-8', className)}
        iconLeading={BracketsPlus}
        isDisabled={isDisabled}
        data-id={`${dataId}-trigger`}
      />

      <MenuPopover placement="bottom end">
        <div className="flex w-64 flex-col gap-1 px-1.5 py-1">
          <InputSearchField
            placeholder="Search"
            value={searchTerm}
            onChange={setSearchTerm}
            data-id={`${dataId}-search`}
            className="mt-[5px] text-sm"
            iconClassName="size-4"
          />
          <MenuList className="max-h-64 overflow-x-hidden">
            {filteredItems.map((item) => (
              <MenuItemPrimitive
                key={item}
                id={item}
                textValue={item}
                onAction={() => onSelect(item)}
                data-id={`${dataId}-item-${item}`}
              >
                <span className="block truncate text-sm">
                  {isFormatTemplateItems ? formatTemplate(item) : item}
                </span>
              </MenuItemPrimitive>
            ))}
          </MenuList>
        </div>
      </MenuPopover>
    </AriaMenuTrigger>
  );
}
